import { useState } from 'react';
import './App.css';
import Api from './axios/api';
import { json } from 'stream/consumers';

interface Usuario {
  id: number;
  nome: string;
  cpf: string;
  telefone: string;
  status: string;
}

function App() {
const [usuarios, setUsuarios] =useState<Usuario[]>([{} as Usuario]);
const BuscarTodosUsuarios= async () => {
  console.log("Buscando todos os usuários...");
 await Api.get("",{
    params:{
    planilha:"usuario"
  }
  }
).then((response)=>setUsuarios(response.data) )  
  .catch((e)=> console.log(e));

}
return (
    <div style={{display:'flex',flexDirection:"column"}}>
      <h1>Hello Mumi Braids!</h1>
      <h4> Site de Agendamento</h4>      
   <table>
      <thead>
        <tr>
          <th>Nome</th>
          <th>Telefone</th>
          <th>Data Agendamento</th>
          <th>Horário</th>
          <th>Dia</th>
        </tr>
      </thead>
      <tbody>
        {usuarios.map((usuario) => (
          <tr key={usuario.id}>
            <td>{usuario.nome}</td>
            <td>{usuario.telefone}</td>
            <td>{usuario.status}</td>
            <td>{usuario.cpf}</td>
            <td>{usuario.id}</td>
          </tr>
        ))}
      </tbody>
    </table>   
    <div>
      <button onClick={BuscarTodosUsuarios}>  Visuaisar</button>
      </div>

    </div> 
  );
}

export default App;
